18	class tb_iw_converter_ax #(
19	  type ax_t = logic,
20	  type id_t = logic
21	);
22	
23	  ax_t  upstream_ax;
24	  id_t  downstream_id;
25	
26	  function new(ax_t upstream_ax);
27	    this.upstream_ax = upstream_ax;
28	    this.downstream_id = 'x;
29	  endfunction
30	
31	  // Compare all fields of two AXs except their IDs.
32	  function bit equals_except_id(ax_t other_ax);
33	    // Override ID field of other AX, then use the field-by-field equality operator.
34	    other_ax.id = this.upstream_ax.id;
35	    return this.upstream_ax == other_ax;
36	  endfunction
37	
38	endclass
